import { Component, ComponentRef, inject } from '@angular/core';
import { AXComponentService } from '@acorex/core/components';

@Component({
  selector: 'app-alert',
  template: `<p>{{ message }}</p>`,
})
export class AlertComponent {
  message = 'Hello from dynamic component!';
}

@Component({
  selector: 'app-host',
  template: `<button (click)="showAlert()">Show Alert</button>`,
})
export class HostComponent {
  private componentService = inject(AXComponentService);
  private alertRef: ComponentRef<AlertComponent> | null = null;

  showAlert() {
    this.alertRef = this.componentService.createFromComponent(AlertComponent);

    // Access and modify the live instance
    this.alertRef.instance.message = 'Updated at runtime';

    // Or use the modern setInput API
    this.alertRef.setInput('message', 'Set via setInput');
  }

  hideAlert() {
    this.alertRef?.destroy();
    this.alertRef = null;
  }
}

import {
  Component,
  EmbeddedViewRef,
  inject,
  TemplateRef,
  viewChild,
} from '@angular/core';
import { AXComponentService } from '@acorex/core/components';

@Component({
  selector: 'app-template-demo',
  template: `
    <ng-template #panel let-name="name">
      <div class="panel">Hello, {{ name }}!</div>
    </ng-template>

    <button (click)="openPanel()">Open Panel</button>
    <button (click)="closePanel()">Close Panel</button>
  `,
})
export class TemplateDemoComponent {
  private componentService = inject(AXComponentService);

  panelTemplate = viewChild.required<TemplateRef<{ name: string }>>('panel');
  private viewRef: EmbeddedViewRef<{ name: string }> | null = null;

  openPanel() {
    this.viewRef = this.componentService.createFromTemplate(this.panelTemplate());

    // Pass context data to the template
    // Note: createFromTemplate does not accept context directly.
    // Use ViewContainerRef.createEmbeddedView on a local container
    // when you need template context, or set data via component inputs.
  }

  closePanel() {
    this.viewRef?.destroy();
    this.viewRef = null;
  }
}

import { Component, ComponentRef, inject, input } from '@angular/core';
import { AXComponentService, AXComponentInputs } from '@acorex/core/components';

@Component({
  selector: 'app-user-card',
  template: `<h3>{{ name() }}</h3><p>{{ email() }}</p>`,
})
export class UserCardComponent {
  name = input<string>('');
  email = input<string>('');
}

@Component({
  selector: 'app-user-host',
  template: `<button (click)="openUserCard()">Show User</button>`,
})
export class UserHostComponent {
  private componentService = inject(AXComponentService);

  openUserCard() {
    const inputs: AXComponentInputs = {
      name: 'Jane Doe',
      email: 'jane@example.com',
    };

    const ref = this.componentService.createFromComponent(UserCardComponent);
    this.applyInputs(ref, inputs);
  }

  private applyInputs(ref: ComponentRef<UserCardComponent>, inputs: AXComponentInputs) {
    Object.entries(inputs).forEach(([key, value]) => {
      ref.setInput(key, value);
    });
  }
}

import { Component, ComponentRef, ElementRef, inject, viewChild } from '@angular/core';
import { AXComponentService } from '@acorex/core/components';

@Component({
  selector: 'app-dialog-body',
  template: `<p>Dialog body content</p>`,
})
export class DialogBodyComponent {}

@Component({
  selector: 'app-dialog-shell',
  template: `
    <div class="dialog">
      <div #contentContainer class="dialog__body"></div>
    </div>
  `,
})
export class DialogShellComponent {
  private componentService = inject(AXComponentService);
  contentContainer = viewChild.required<ElementRef<HTMLElement>>('contentContainer');

  renderBody() {
    const ref = this.componentService.createFromComponent(DialogBodyComponent);
    const hostElement = ref.location.nativeElement;

    // Move the component's host element into the dialog body
    this.contentContainer().nativeElement.appendChild(hostElement);

    return ref;
  }
}

import { Component, ComponentRef, inject, OnDestroy } from '@angular/core';
import { AXComponentService } from '@acorex/core/components';

@Component({
  selector: 'app-overlay-host',
  template: `<button (click)="toggle()">Toggle</button>`,
})
export class OverlayHostComponent implements OnDestroy {
  private componentService = inject(AXComponentService);
  private activeRef: ComponentRef<unknown> | null = null;

  toggle() {
    if (this.activeRef) {
      this.dispose();
    } else {
      this.activeRef = this.componentService.createFromComponent(MyOverlayComponent);
    }
  }

  private dispose() {
    this.activeRef?.destroy();
    this.activeRef = null;
  }

  ngOnDestroy() {
    this.dispose();
  }
}

@Component({ selector: 'app-my-overlay', template: `<p>Overlay</p>` })
class MyOverlayComponent {}

import { Component, inject } from '@angular/core';
import { AXOverlayService } from '@acorex/cdk/overlay';

@Component({
  selector: 'app-tooltip-content',
  template: `<span>Tooltip text</span>`,
})
export class TooltipContentComponent {}

@Component({
  selector: 'app-tooltip-trigger',
  template: `<button #anchor (click)="showTooltip(anchor)">Hover me</button>`,
})
export class TooltipTriggerComponent {
  private overlayService = inject(AXOverlayService);

  async showTooltip(anchor: HTMLElement) {
    const ref = await this.overlayService.create(TooltipContentComponent, {
      anchorOptions: { anchor, placement: 'top' },
      backdrop: { enabled: false },
    });

    // ref.dispose() handles component destruction and DOM cleanup
    setTimeout(() => ref.dispose(), 3000);
  }
}
